import React, { useEffect, useState } from 'react';
import { Button, Slideout } from '@linm-soft-org/linm-web-common-components';
import { useNavigate } from 'react-router-dom';
import { wmsService } from '../../services/kho/wmsService';
import type { StockLedgerLineDto } from '../../services/kho/models';
import { KHO_PATHS } from '../../appPaths';
import { khoReportPageLabels } from '../../constants/khoReportPageLabels';
import { formatDate, formatMoneyVnd, formatNumber } from '../../utils/formatters';
import { getApiErrorMessage } from '../../utils/getApiErrorMessage';
import { WmsSourceDocumentSlideout } from './WmsSourceDocumentSlideout';
import styles from './WmsSourceDocumentSlideout.module.css';
import erp from '../../styles/erpPage.module.css';

const labels = khoReportPageLabels.tonKho;

export type StockMaterialLedgerSlideoutProps = {
  isOpen: boolean;
  onClose: () => void;
  materialCode: string;
  materialName?: string;
  warehouseId?: string;
  asOfDate?: string;
  testIdPrefix: string;
};

export const StockMaterialLedgerSlideout: React.FC<StockMaterialLedgerSlideoutProps> = ({
  isOpen,
  onClose,
  materialCode,
  materialName,
  warehouseId,
  asOfDate,
  testIdPrefix,
}) => {
  const navigate = useNavigate();
  const [items, setItems] = useState<StockLedgerLineDto[]>([]);
  const [loading, setLoading] = useState(false);
  const [loadError, setLoadError] = useState<string | null>(null);
  const [docSlideout, setDocSlideout] = useState<StockLedgerLineDto | null>(null);

  useEffect(() => {
    if (!isOpen || !materialCode.trim()) return;
    let cancelled = false;
    setLoading(true);
    setLoadError(null);
    const t = setTimeout(() => {
      wmsService.getStockLedger({
        materialCode: materialCode.trim(),
        warehouseId: warehouseId || undefined,
        toDate: asOfDate ? `${asOfDate}T23:59:59.999Z` : undefined,
      })
        .then(rows => { if (!cancelled) setItems(rows); })
        .catch(err => {
          if (!cancelled) {
            setLoadError(getApiErrorMessage(err, labels.ledgerLoadError));
            setItems([]);
          }
        })
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [isOpen, materialCode, warehouseId, asOfDate]);

  const title = materialName
    ? `${labels.ledgerSlideoutTitle}: ${materialCode} — ${materialName}`
    : `${labels.ledgerSlideoutTitle}: ${materialCode}`;

  const handleOpenFull = () => {
    const qs = new URLSearchParams({ materialCode });
    if (warehouseId) qs.set('warehouseId', warehouseId);
    onClose();
    navigate(`${KHO_PATHS.theKho}?${qs.toString()}`);
  };

  const footer = (
    <div className={styles.footerBar}>
      <Button variant="secondary" onClick={onClose} data-testid={`${testIdPrefix}-ledger-slideout-close`}>
        {labels.slideoutClose}
      </Button>
      <Button variant="primary" onClick={handleOpenFull} data-testid={`${testIdPrefix}-ledger-slideout-open-full`}>
        {labels.slideoutOpenFull}
      </Button>
    </div>
  );

  return (
    <>
      <Slideout
        isOpen={isOpen}
        onClose={onClose}
        title={title}
        width="min(720px, 92vw)"
        customFooter={footer}
        data-testid={`${testIdPrefix}-ledger-slideout`}
      >
        {loading ? (
          <div className={styles.previewBody}>{labels.ledgerLoading}</div>
        ) : loadError ? (
          <div className={styles.previewBody}>{loadError}</div>
        ) : (
          <div className={erp.tableWrapper} data-testid={`${testIdPrefix}-ledger-slideout-grid`}>
            <table className={erp.table}>
              <thead>
                <tr>
                  <th>Ngày</th>
                  <th>Loại</th>
                  <th>Số CT</th>
                  <th className={erp.colRight}>Nhập</th>
                  <th className={erp.colRight}>Xuất</th>
                  <th className={erp.colRight}>ĐG</th>
                </tr>
              </thead>
              <tbody>
                {items.length === 0 ? (
                  <tr><td colSpan={6}><div className={erp.empty}>{labels.ledgerEmpty}</div></td></tr>
                ) : items.map((row, i) => (
                  <tr
                    key={row.id ?? i}
                    onDoubleClick={() => {
                      if (row.canOpenSourceDocument && row.sourceDocumentId) {
                        setDocSlideout(row);
                      }
                    }}
                    style={{ cursor: row.canOpenSourceDocument ? 'pointer' : 'default' }}
                  >
                    <td>{formatDate(row.movementDate)}</td>
                    <td>{row.movementType}</td>
                    <td>{row.voucherCode ?? '—'}</td>
                    <td className={erp.colRight}>{formatNumber(row.inQty)}</td>
                    <td className={erp.colRight}>{formatNumber(row.outQty)}</td>
                    <td className={erp.colRight}>{formatMoneyVnd(row.unitPrice)}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </Slideout>
      <WmsSourceDocumentSlideout
        isOpen={docSlideout != null}
        onClose={() => setDocSlideout(null)}
        documentType={docSlideout?.sourceDocumentType ?? null}
        documentId={docSlideout?.sourceDocumentId ?? null}
        sourceDocumentViewUrl={docSlideout?.sourceDocumentViewUrl}
        voucherCode={docSlideout?.voucherCode ?? undefined}
        title={labels.slideoutTitle}
        returnTitle={materialName || materialCode}
        closeLabel={labels.slideoutClose}
        openFullLabel={labels.slideoutOpenFull}
        testIdPrefix={`${testIdPrefix}-ledger-doc`}
      />
    </>
  );
};
